var CORP_VIEW='leads';var CORP_ACTIVE_ID=null;function loadCorporateSection(){renderCorporateSubtabs();showCorporateTab(CORP_VIEW);}
function renderCorporateSubtabs(){var host=document.getElementById('corporateSubtabs');if(!host)return;host.innerHTML='<button class="corp-subtab'+(CORP_VIEW==='leads'?' active':'')+'" data-atp-call="showCorporateTab" data-args=\'["leads"]\' style="padding:7px 14px;font-size:12px;font-weight:700;background:'+(CORP_VIEW==='leads'?'rgba(122,194,49,.12)':'transparent')+';color:'+(CORP_VIEW==='leads'?'#7AC231':'#888')+';border:1px solid '+(CORP_VIEW==='leads'?'rgba(122,194,49,.3)':'#2a2a2a')+';border-radius:8px;cursor:pointer">Leads pipeline</button>'+'<button class="corp-subtab'+(CORP_VIEW==='accounts'?' active':'')+'" data-atp-call="showCorporateTab" data-args=\'["accounts"]\' style="padding:7px 14px;font-size:12px;font-weight:700;background:'+(CORP_VIEW==='accounts'?'rgba(122,194,49,.12)':'transparent')+';color:'+(CORP_VIEW==='accounts'?'#7AC231':'#888')+';border:1px solid '+(CORP_VIEW==='accounts'?'rgba(122,194,49,.3)':'#2a2a2a')+';border-radius:8px;cursor:pointer">Active accounts</button>';}
function showCorporateTab(tab){CORP_VIEW=tab;renderCorporateSubtabs();if(tab==='leads')loadCorporateLeads();else if(tab==='accounts')loadCorporateAccounts();}
function loadCorporateLeads(){var host=document.getElementById('corporateBody');if(!host)return;host.innerHTML='<div style="padding:30px;color:#555;text-align:center">Loading leads…</div>';fetch(ATP_API+'/corporate/admin/leads',{headers:{Authorization:'Bearer '+getToken()}}).then(function(r){return r.json();}).then(function(d){renderCorporateLeads((d&&d.leads)||[]);}).catch(function(){host.innerHTML='<div style="padding:30px;color:#f87171;text-align:center">Failed. Migration run?</div>';});}
function renderCorporateLeads(leads){var host=document.getElementById('corporateBody');if(!host)return;var stages=['new','qualified','pitch_sent','negotiating','won','lost'];var stageColors={new:'#888',qualified:'#3b82f6',pitch_sent:'#f59e0b',negotiating:'#f5c042',won:'#7AC231',lost:'#ef4444'};var byStage={};stages.forEach(function(s){byStage[s]=[];});leads.forEach(function(l){if(byStage[l.stage])byStage[l.stage].push(l);});var pipelineValue=leads.filter(function(l){return['qualified','pitch_sent','negotiating'].includes(l.stage);}).reduce(function(s,l){return s+(l.estimated_aed||0);},0);var wonValue=leads.filter(function(l){return l.stage==='won';}).reduce(function(s,l){return s+(l.estimated_aed||0);},0);var html='<div style="display:grid;grid-template-columns:repeat(4,1fr);gap:14px;margin-bottom:18px">'+'<div style="background:#0f0f0f;border:1px solid #1e1e1e;border-radius:10px;padding:18px"><div style="font-size:10px;color:#888;letter-spacing:.12em;text-transform:uppercase;font-weight:600">Total leads</div><div style="font-family:var(--ff-display,sans-serif);font-size:32px;font-weight:900;color:#fff">'+leads.length+'</div></div>'+'<div style="background:#0f0f0f;border:1px solid rgba(245,158,11,.32);border-radius:10px;padding:18px"><div style="font-size:10px;color:#f59e0b;letter-spacing:.12em;text-transform:uppercase;font-weight:600">In pipeline (AED MRR)</div><div style="font-family:var(--ff-display,sans-serif);font-size:32px;font-weight:900;color:#f59e0b">'+pipelineValue.toLocaleString()+'</div></div>'+'<div style="background:#0f0f0f;border:1px solid rgba(122,194,49,.32);border-radius:10px;padding:18px"><div style="font-size:10px;color:#7AC231;letter-spacing:.12em;text-transform:uppercase;font-weight:600">Won (AED MRR)</div><div style="font-family:var(--ff-display,sans-serif);font-size:32px;font-weight:900;color:#7AC231">'+wonValue.toLocaleString()+'</div></div>'+'<div style="background:#0f0f0f;border:1px solid #1e1e1e;border-radius:10px;padding:18px;display:flex;align-items:center;justify-content:center"><button class="admin-btn admin-btn-primary" data-atp-call="newCorporateLeadForm" style="font-size:13px;padding:10px 20px">+ Add lead</button></div>'+'</div>'+'<div id="corpLeadFormWrap"></div>'+'<div style="display:grid;grid-template-columns:repeat(6,1fr);gap:10px;overflow-x:auto">';stages.forEach(function(stage){var stageLeads=byStage[stage];html+='<div style="background:#0a0a0a;border:1px solid #1a1a1a;border-radius:10px;padding:12px;min-width:220px">'+'<div style="display:flex;align-items:center;gap:6px;margin-bottom:10px;padding-bottom:8px;border-bottom:1px solid #1a1a1a">'+'<span style="width:8px;height:8px;border-radius:50%;background:'+stageColors[stage]+'"></span>'+'<span style="font-size:10px;color:'+stageColors[stage]+';font-weight:800;letter-spacing:.08em;text-transform:uppercase">'+stage.replace('_',' ')+'</span>'+'<span style="margin-left:auto;font-size:11px;color:#666">'+stageLeads.length+'</span>'+'</div>';if(!stageLeads.length){html+='<div style="font-size:11px;color:#555;padding:14px 0;text-align:center">Empty</div>';}else{html+=stageLeads.map(function(l){return'<div style="background:#0f0f0f;border:1px solid #1e1e1e;border-radius:8px;padding:10px;margin-bottom:6px;cursor:pointer" data-atp-call="editCorporateLead" data-args=\'["'+l.id+'"]\'>'+'<div style="font-size:12px;color:#fff;font-weight:700;margin-bottom:4px">'+_esc(l.company_name)+'</div>'+
(l.contact_name?'<div style="font-size:10px;color:#888">'+_esc(l.contact_name)+'</div>':'')+
(l.estimated_aed?'<div style="font-size:11px;color:#7AC231;font-weight:700;margin-top:6px">AED '+l.estimated_aed.toLocaleString()+' MRR</div>':'')+
(l.next_action?'<div style="font-size:10px;color:#888;margin-top:6px;font-style:italic">→ '+_esc(l.next_action.slice(0,50))+'</div>':'')+'</div>';}).join('');}
html+='</div>';});html+='</div>';host.innerHTML=html;}
function newCorporateLeadForm(){var wrap=document.getElementById('corpLeadFormWrap');if(!wrap)return;wrap.innerHTML='<div style="background:#0d1a0a;border:1px solid #1f3a0d;border-radius:10px;padding:18px;margin-bottom:14px">'+'<div style="font-family:var(--ff-display,sans-serif);font-size:16px;font-weight:800;color:#7AC231;text-transform:uppercase;margin-bottom:12px">New lead</div>'+'<div style="display:grid;grid-template-columns:2fr 1fr;gap:10px;margin-bottom:10px">'+'<div><label class="admin-form-label">Company *</label><input class="admin-form-input" id="leadCompany" placeholder="Acme Corp"></div>'+'<div><label class="admin-form-label">Industry</label><input class="admin-form-input" id="leadIndustry" placeholder="Financial services"></div>'+'</div>'+'<div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:10px;margin-bottom:10px">'+'<div><label class="admin-form-label">Contact name</label><input class="admin-form-input" id="leadContactName"></div>'+'<div><label class="admin-form-label">Email</label><input class="admin-form-input" id="leadEmail"></div>'+'<div><label class="admin-form-label">Phone</label><input class="admin-form-input" id="leadPhone"></div>'+'</div>'+'<div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:10px;margin-bottom:10px">'+'<div><label class="admin-form-label"># employees</label><input class="admin-form-input" type="number" id="leadEmployees"></div>'+'<div><label class="admin-form-label">Estimated AED MRR</label><input class="admin-form-input" type="number" id="leadAed" placeholder="24000"></div>'+'<div><label class="admin-form-label">Source</label><input class="admin-form-input" id="leadSource" placeholder="LinkedIn / referral / cold"></div>'+'</div>'+'<div style="display:grid;grid-template-columns:2fr 1fr;gap:10px;margin-bottom:10px">'+'<div><label class="admin-form-label">Next action</label><input class="admin-form-input" id="leadNextAction" placeholder="Send pitch deck this Friday"></div>'+'<div><label class="admin-form-label">Next action date</label><input class="admin-form-input" type="date" id="leadNextDate"></div>'+'</div>'+'<div style="margin-bottom:10px"><label class="admin-form-label">Notes</label><textarea class="admin-form-input" id="leadNotes" rows="2"></textarea></div>'+'<div style="display:flex;gap:8px">'+'<button class="admin-btn admin-btn-primary" data-atp-call="saveCorporateLead" style="font-size:12px">Save lead</button>'+'<button class="admin-btn" data-atp-call="cancelCorpLeadForm" style="font-size:12px">Cancel</button>'+'</div>'+'</div>';}
function cancelCorpLeadForm(){var w=document.getElementById('corpLeadFormWrap');if(w)w.innerHTML='';}
function saveCorporateLead(){var body={company_name:document.getElementById('leadCompany').value.trim(),industry:document.getElementById('leadIndustry').value.trim(),contact_name:document.getElementById('leadContactName').value.trim(),contact_email:document.getElementById('leadEmail').value.trim(),contact_phone:document.getElementById('leadPhone').value.trim(),estimated_employees:document.getElementById('leadEmployees').value,estimated_aed:document.getElementById('leadAed').value,source:document.getElementById('leadSource').value.trim(),next_action:document.getElementById('leadNextAction').value.trim(),next_action_date:document.getElementById('leadNextDate').value||null,notes:document.getElementById('leadNotes').value.trim(),};if(!body.company_name){showToast('❌ Company required',true);return;}
fetch(ATP_API+'/corporate/admin/leads',{method:'POST',headers:{'Content-Type':'application/json',Authorization:'Bearer '+getToken()},body:JSON.stringify(body),}).then(function(r){return r.json();}).then(function(res){if(res.error){showToast('❌ '+res.error,true);return;}
showToast('✅ Lead added');cancelCorpLeadForm();loadCorporateLeads();});}
function editCorporateLead(e,btn){var id=JSON.parse(btn.getAttribute('data-args')||'[]')[0];var stages=[{v:'new',l:'New'},{v:'qualified',l:'Qualified'},{v:'pitch_sent',l:'Pitch sent'},{v:'negotiating',l:'Negotiating'},{v:'won',l:'✓ Won'},{v:'lost',l:'✗ Lost'},];var newStage=prompt('Advance stage to:\n\n'+stages.map(function(s,i){return(i+1)+'. '+s.l;}).join('\n')+'\n\nType number (1-6):');if(!newStage)return;var idx=parseInt(newStage,10)-1;if(idx<0||idx>=stages.length){showToast('❌ Invalid',true);return;}
fetch(ATP_API+'/corporate/admin/leads/'+id,{method:'PATCH',headers:{'Content-Type':'application/json',Authorization:'Bearer '+getToken()},body:JSON.stringify({stage:stages[idx].v}),}).then(function(r){return r.json();}).then(function(res){if(res.error){showToast('❌ '+res.error,true);return;}
showToast('✅ Stage updated to '+stages[idx].l);loadCorporateLeads();});}
function loadCorporateAccounts(){var host=document.getElementById('corporateBody');if(!host)return;host.innerHTML='<div style="padding:30px;color:#555;text-align:center">Loading accounts…</div>';fetch(ATP_API+'/corporate/admin/accounts',{headers:{Authorization:'Bearer '+getToken()}}).then(function(r){return r.json();}).then(function(d){renderCorporateAccounts((d&&d.accounts)||[]);}).catch(function(){host.innerHTML='<div style="padding:30px;color:#f87171;text-align:center">Failed</div>';});}
function renderCorporateAccounts(accounts){var host=document.getElementById('corporateBody');if(!host)return;var origin=window.location.origin;var totalMRR=accounts.filter(function(a){return a.status==='active';}).reduce(function(s,a){return s+(a.monthly_fee_aed||0);},0);var totalEmployees=accounts.reduce(function(s,a){return s+(a.employee_count||0);},0);var html='<div style="display:grid;grid-template-columns:repeat(3,1fr) auto;gap:14px;margin-bottom:18px">'+'<div style="background:#0f0f0f;border:1px solid #1e1e1e;border-radius:10px;padding:18px"><div style="font-size:10px;color:#888;letter-spacing:.12em;text-transform:uppercase;font-weight:600">Active accounts</div><div style="font-family:var(--ff-display,sans-serif);font-size:32px;font-weight:900;color:#fff">'+accounts.filter(function(a){return a.status==='active';}).length+'</div></div>'+'<div style="background:#0f0f0f;border:1px solid rgba(122,194,49,.32);border-radius:10px;padding:18px"><div style="font-size:10px;color:#7AC231;letter-spacing:.12em;text-transform:uppercase;font-weight:600">Total MRR</div><div style="font-family:var(--ff-display,sans-serif);font-size:32px;font-weight:900;color:#7AC231">AED '+totalMRR.toLocaleString()+'</div></div>'+'<div style="background:#0f0f0f;border:1px solid #1e1e1e;border-radius:10px;padding:18px"><div style="font-size:10px;color:#888;letter-spacing:.12em;text-transform:uppercase;font-weight:600">Employees enrolled</div><div style="font-family:var(--ff-display,sans-serif);font-size:32px;font-weight:900;color:#fff">'+totalEmployees+'</div></div>'+'<div style="display:flex;align-items:center;justify-content:center"><button class="admin-btn admin-btn-primary" data-atp-call="newCorporateAccountForm" style="font-size:13px;padding:10px 20px;white-space:nowrap">+ New account</button></div>'+'</div>'+'<div id="corpAccountFormWrap"></div>';if(!accounts.length){html+='<div style="padding:40px;color:#555;text-align:center;border:1px dashed #2a2a2a;border-radius:10px">No corporate accounts yet. Close a lead and create one here.</div>';}else{html+=accounts.map(function(a){var statusColor=a.status==='active'?'#7AC231':(a.status==='paused'?'#f59e0b':'#666');var inviteUrl=a.latest_token?(origin+'/corporate/join/'+a.latest_token):null;return'<div style="background:#0f0f0f;border:1px solid #1e1e1e;border-radius:10px;padding:18px;margin-bottom:10px">'+'<div style="display:flex;justify-content:space-between;align-items:flex-start;gap:14px">'+'<div style="flex:1">'+'<div style="display:flex;align-items:center;gap:10px;margin-bottom:6px">'+'<span style="font-family:var(--ff-display,sans-serif);font-size:18px;font-weight:800;color:#fff">'+_esc(a.company_name)+'</span>'+'<span style="font-size:9px;font-weight:800;letter-spacing:.08em;text-transform:uppercase;color:'+statusColor+';border:1px solid '+statusColor+';padding:2px 7px;border-radius:4px">'+a.status+'</span>'+'</div>'+'<div style="font-size:11px;color:#888">'+'<strong style="color:#7AC231">AED '+(a.monthly_fee_aed||0).toLocaleString()+'/mo</strong>'+' · '+(a.employee_count||0)+' / '+(a.employee_cap||'∞')+' employees'+' · '+(a.contact_email||'no contact')+'</div>'+
(inviteUrl?'<div style="margin-top:10px;display:flex;gap:6px;align-items:center"><code style="background:#0a0a0a;padding:4px 10px;border-radius:4px;color:#7AC231;font-size:11px;flex:1;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">'+inviteUrl+'</code>'+'<button class="admin-btn" onclick="navigator.clipboard.writeText(\''+inviteUrl+'\').then(function(){showToast(\'✅ Copied\')})" style="font-size:11px;padding:4px 10px">Copy</button>'+'</div>':'')+'</div>'+'<div style="display:flex;flex-direction:column;gap:6px">'+'<a class="admin-btn" href="/corporate/dashboard/'+a.slug+'" target="_blank" style="font-size:11px;padding:6px 12px;text-decoration:none">📊 Buyer view</a>'+'<button class="admin-btn" data-atp-call="viewCorporateEngagement" data-args=\'["'+a.id+'","'+_esc(a.company_name)+'"]\' style="font-size:11px;padding:6px 12px">📈 Engagement</button>'+'</div>'+'</div>'+'<div id="engagement-'+a.id+'"></div>'+'</div>';}).join('');}
host.innerHTML=html;}
function newCorporateAccountForm(){var wrap=document.getElementById('corpAccountFormWrap');if(!wrap)return;wrap.innerHTML='<div style="background:#0d1a0a;border:1px solid #1f3a0d;border-radius:10px;padding:18px;margin-bottom:14px">'+'<div style="font-family:var(--ff-display,sans-serif);font-size:16px;font-weight:800;color:#7AC231;text-transform:uppercase;margin-bottom:12px">New corporate account</div>'+'<div style="display:grid;grid-template-columns:2fr 1fr 1fr;gap:10px;margin-bottom:10px">'+'<div><label class="admin-form-label">Company *</label><input class="admin-form-input" id="accCompany" placeholder="Acme Corp"></div>'+'<div><label class="admin-form-label">Industry</label><input class="admin-form-input" id="accIndustry"></div>'+'<div><label class="admin-form-label">Slug (URL part)</label><input class="admin-form-input" id="accSlug" placeholder="auto"></div>'+'</div>'+'<div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:10px;margin-bottom:10px">'+'<div><label class="admin-form-label">Contact name</label><input class="admin-form-input" id="accContactName"></div>'+'<div><label class="admin-form-label">Email</label><input class="admin-form-input" id="accEmail"></div>'+'<div><label class="admin-form-label">Phone</label><input class="admin-form-input" id="accPhone"></div>'+'</div>'+'<div style="display:grid;grid-template-columns:1fr 1fr 1fr 1fr;gap:10px;margin-bottom:10px">'+'<div><label class="admin-form-label">Employee cap</label><input class="admin-form-input" type="number" id="accCap" placeholder="200"></div>'+'<div><label class="admin-form-label">Monthly fee (AED) *</label><input class="admin-form-input" type="number" id="accMonthly" placeholder="24000"></div>'+'<div><label class="admin-form-label">Start date</label><input class="admin-form-input" type="date" id="accStart"></div>'+'<div><label class="admin-form-label">End date</label><input class="admin-form-input" type="date" id="accEnd"></div>'+'</div>'+'<div style="margin-bottom:10px"><label class="admin-form-label">Notes</label><textarea class="admin-form-input" id="accNotes" rows="2"></textarea></div>'+'<div style="display:flex;gap:8px">'+'<button class="admin-btn admin-btn-primary" data-atp-call="saveCorporateAccount" style="font-size:12px">Create account + signup token</button>'+'<button class="admin-btn" data-atp-call="cancelCorpAccountForm" style="font-size:12px">Cancel</button>'+'</div>'+'</div>';}
function cancelCorpAccountForm(){var w=document.getElementById('corpAccountFormWrap');if(w)w.innerHTML='';}
function saveCorporateAccount(){var body={company_name:document.getElementById('accCompany').value.trim(),industry:document.getElementById('accIndustry').value.trim(),slug:document.getElementById('accSlug').value.trim(),contact_name:document.getElementById('accContactName').value.trim(),contact_email:document.getElementById('accEmail').value.trim(),contact_phone:document.getElementById('accPhone').value.trim(),employee_cap:document.getElementById('accCap').value,monthly_fee_aed:document.getElementById('accMonthly').value,start_date:document.getElementById('accStart').value||null,end_date:document.getElementById('accEnd').value||null,notes:document.getElementById('accNotes').value.trim(),};if(!body.company_name||!body.monthly_fee_aed){showToast('❌ Company + monthly fee required',true);return;}
fetch(ATP_API+'/corporate/admin/accounts',{method:'POST',headers:{'Content-Type':'application/json',Authorization:'Bearer '+getToken()},body:JSON.stringify(body),}).then(function(r){return r.json();}).then(function(res){if(res.error){showToast('❌ '+res.error,true);return;}
var url=window.location.origin+'/corporate/join/'+res.signup_token;showToast('✅ Account created · invite URL copied');try{navigator.clipboard.writeText(url);}catch(e){}
cancelCorpAccountForm();loadCorporateAccounts();});}
function viewCorporateEngagement(e,btn){var args=JSON.parse(btn.getAttribute('data-args')||'[]');var id=args[0];var host=document.getElementById('engagement-'+id);if(!host)return;if(host.innerHTML){host.innerHTML='';return;}
host.innerHTML='<div style="padding:14px;color:#555">Loading engagement…</div>';fetch(ATP_API+'/corporate/admin/accounts/'+id+'/engagement',{headers:{Authorization:'Bearer '+getToken()}}).then(function(r){return r.json();}).then(function(d){var t=d.totals||{};var a=d.activity||{};var participation=t.active_employees?Math.round(100*(a.unique_30d||0)/t.active_employees):0;host.innerHTML='<div style="background:#0a0a0a;border:1px solid #1e1e1e;border-radius:8px;padding:14px;margin-top:12px;display:grid;grid-template-columns:repeat(4,1fr);gap:12px">'+'<div><div style="font-size:9px;color:#888;letter-spacing:.1em;text-transform:uppercase">Total enrolled</div><div style="font-family:var(--ff-display,sans-serif);font-size:22px;font-weight:900;color:#fff">'+(t.total_employees||0)+'</div></div>'+'<div><div style="font-size:9px;color:#888;letter-spacing:.1em;text-transform:uppercase">Active 30d (unique)</div><div style="font-family:var(--ff-display,sans-serif);font-size:22px;font-weight:900;color:#7AC231">'+(a.unique_30d||0)+' <span style="font-size:11px;color:#888;font-weight:500;font-family:inherit">/ '+participation+'%</span></div></div>'+'<div><div style="font-size:9px;color:#888;letter-spacing:.1em;text-transform:uppercase">Check-ins 30d</div><div style="font-family:var(--ff-display,sans-serif);font-size:22px;font-weight:900;color:#fff">'+(a.checkins_30d||0)+'</div></div>'+'<div><div style="font-size:9px;color:#888;letter-spacing:.1em;text-transform:uppercase">Check-ins 7d</div><div style="font-family:var(--ff-display,sans-serif);font-size:22px;font-weight:900;color:#fff">'+(a.checkins_7d||0)+'</div></div>'+'</div>';});}
function _esc(s){return String(s==null?'':s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;').replace(/'/g,'&#39;');}